     2→
     3→import Link from "next/link";
     4→import { usePathname } from "next/navigation";
     5→import { ArrowRight } from "lucide-react";
     6→import { K3rnLogo } from "@/components/ui/k3rn-logo";
     7→import { LanguageSelector } from "@/components/ui/language-selector";
     8→import { UserNav } from "@/components/layout/user-nav";
     9→import { cn } from "@/lib/utils";
    10→
    11→const APP_NAV_LINKS = [
    12→    { label: "Capture", href: "/capture" },
    13→    { label: "Dossiers", href: "/workspace" },
    14→];
    15→
    16→interface SiteHeaderProps {
    17→    variant?: "public" | "app";
    18→    className?: string;
    19→}
    20→
    21→export function SiteHeader({ variant = "public", className }: SiteHeaderProps) {
    22→    const pathname = usePathname();
    23→    const isApp = variant === "app";
    24→
    25→    return (
    26→        <header
    27→            className={cn(
    28→                "sticky top-0 z-50 w-full border-b border-[--color-border-subtle] bg-[#22242B]/90 backdrop-blur-xl saturate-[1.2] supports-[backdrop-filter]:bg-[#22242B]/70 transition-all duration-300",
    29→                className
    30→            )}
    31→        >
    32→            <div className="max-w-7xl mx-auto flex h-16 items-center justify-between px-6">
    33→                {/* Left: Brand + Nav */}
    34→                <div className="flex items-center gap-6">
    35→                    <Link
    36→                        href={isApp ? "/workspace" : "/"}
    37→                        className="flex items-center gap-2 transition-opacity hover:opacity-80 group cursor-pointer"
    38→                    >
    39→                        <K3rnLogo size="sm" className={cn("transition-transform duration-500 group-hover:rotate-180", !isApp && "brightness-150")} />
    40→                    </Link>
    41→
    42→                    {isApp && (
    43→                        <>
    44→                            <div className="h-5 w-[1px] bg-[--color-border-default]" />
