    56→        { label: "Probleme", score: Math.min(10, Math.round(base * 1.1)) },
    57→        { label: "Marche", score: Math.min(10, Math.round(base * 0.95)) },
    58→        { label: "Differenciation", score: Math.min(10, Math.round(base * 1.2)) },
    59→        { label: "Faisabilite", score: Math.min(10, Math.round(base * 0.9)) },
    60→        { label: "Business Model", score: Math.min(10, Math.round(base * 1.05)) },
    61→        { label: "Founder Fit", score: Math.min(10, Math.round(base * 1.0)) },
    62→    ];
    63→}
