     1→/**
     2→ * K3RN.LABS — POST /api/analysis
     3→ * Analyse canonique d'une idée via Claude API
     4→ *
     5→ * Pipeline :
     6→ * 1. Validation input (JSON Schema)
     7→ * 2. Assemblage prompt (system + orchestrator + experts + constraints)
     8→ * 3. Appel Claude API
     9→ * 4. Parsing réponse JSON
    10→ * 5. Validation output LLM (JSON Schema)
    11→ * 6. Calcul score global (formule canonique serveur)
    12→ * 7. Détermination décision (logique serveur)
    13→ * 8. Détection enrichissement
    14→ * 9. Retour réponse conforme
    15→ */
    16→
    17→import { NextResponse } from 'next/server';
    18→import Anthropic from '@anthropic-ai/sdk';
    19→import { validateAnalysisInput, validateLlmRawOutput } from '@/lib/analysis/validators';
    20→import { calculateGlobalScore } from '@/lib/analysis/scoring';
    21→import { determineDecision } from '@/lib/analysis/decision';
    22→import { computeEnrichmentDecision } from '@/lib/analysis/enrichment';
    23→import { CANONICAL_WEIGHTS, SCHEMA_VERSION } from '@/lib/analysis/constants';
    24→import { assembleSystemPrompt, buildUserMessage, CURRENT_VERSION } from '@/lib/analysis/prompts/registry';
    25→import type { AnalysisOutput, AnalysisAxes, ApiError } from '@/lib/analysis/types';
    26→
    27→// ─── Claude API client ──────────────────────────────────────────
    28→const anthropic = new Anthropic({
    29→  apiKey: process.env.ANTHROPIC_API_KEY,
    30→});
    31→
    32→const AI_MODEL = process.env.AI_MODEL || 'claude-opus-4-20250918';
    33→const AI_TEMPERATURE = parseFloat(process.env.AI_TEMPERATURE || '0.2');
    34→const AI_TIMEOUT_MS = parseInt(process.env.AI_TIMEOUT_MS || '30000', 10);
    35→
    36→// ═══════════════════════════════════════════════════════════════════
    37→// POST /api/analysis
    38→// ═══════════════════════════════════════════════════════════════════
    39→
    40→export async function POST(req: Request) {
    41→  const startTime = Date.now();
    42→
    43→  try {
    44→    // ─── 1. Parse request body ──────────────────────────────────
    45→    let body: unknown;
    46→    try {
    47→      body = await req.json();
    48→    } catch {
    49→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Request body is not valid JSON');
    50→    }
    51→
    52→    // ─── 2. Validate input against canonical schema ─────────────
    53→    const inputValidation = validateAnalysisInput(body);
    54→    if (!inputValidation.valid) {
    55→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', inputValidation.errors!.join('; '));
    56→    }
    57→
    58→    const input = inputValidation.data!;
    59→
    60→    // ─── 3. Check idea state ────────────────────────────────────
    61→    if (input.idea.state !== 'CAPTURED' && input.idea.state !== 'ANALYZED') {
    62→      return errorResponse(409, 'IDEA_STATE_CONFLICT', `Idea state "${input.idea.state}" is not valid for initial analysis`);
    63→    }
    64→
    65→    // ─── 4. Assemble prompts ────────────────────────────────────
    66→    const systemPrompt = assembleSystemPrompt(CURRENT_VERSION);
    67→    const userMessage = buildUserMessage({
    68→      text: input.inputs.text?.content,
    69→      links: input.inputs.links,
    70→      files: input.inputs.files,
    71→      experienceLevel: input.context?.experience_level,
    72→    });
    73→
    74→    // ─── 5. Call Claude API ─────────────────────────────────────
    75→    let llmResponse: string;
    76→    try {
    77→      const message = await anthropic.messages.create({
    78→        model: AI_MODEL,
    79→        max_tokens: 4096,
    80→        temperature: AI_TEMPERATURE,
    81→        system: systemPrompt,
    82→        messages: [{ role: 'user', content: userMessage }],
    83→      });
    84→
    85→      // Extract text content
    86→      const textBlock = message.content.find((block) => block.type === 'text');
    87→      if (!textBlock || textBlock.type !== 'text') {
    88→        return errorResponse(500, 'ANALYSIS_OUTPUT_INVALID', 'LLM returned no text content');
    89→      }
    90→      llmResponse = textBlock.text;
    91→    } catch (error: unknown) {
    92→      const err = error as Error & { status?: number };
    93→      if (err.status === 429) {
    94→        return errorResponse(429, 'AI_RATE_LIMITED', 'AI API rate limit exceeded');
    95→      }
    96→      if (err.name === 'TimeoutError' || err.message?.includes('timeout')) {
    97→        return errorResponse(504, 'AI_TIMEOUT', 'AI analysis timed out');
    98→      }
    99→      console.error('Claude API error:', err);
   100→      return errorResponse(500, 'AI_CALL_FAILED', `Claude API error: ${err.message}`);
   101→    }
   102→
   103→    // ─── 6. Parse JSON response ─────────────────────────────────
   104→    let parsedLlm: unknown;
   105→    try {
   106→      // Handle potential markdown code block wrapping
   107→      let jsonStr = llmResponse.trim();
   108→      if (jsonStr.startsWith('```json')) {
   109→        jsonStr = jsonStr.slice(7);
   110→      } else if (jsonStr.startsWith('```')) {
   111→        jsonStr = jsonStr.slice(3);
   112→      }
   113→      if (jsonStr.endsWith('```')) {
   114→        jsonStr = jsonStr.slice(0, -3);
   115→      }
   116→      parsedLlm = JSON.parse(jsonStr.trim());
   117→    } catch {
   118→      console.error('LLM JSON parse error. Raw response:', llmResponse.substring(0, 500));
   119→      return errorResponse(500, 'ANALYSIS_OUTPUT_INVALID', 'LLM output is not valid JSON');
   120→    }
   121→
   122→    // ─── 7. Validate LLM output against schema ─────────────────
   123→    const llmValidation = validateLlmRawOutput(parsedLlm);
   124→    if (!llmValidation.valid) {
   125→      console.error('LLM output validation errors:', llmValidation.errors);
   126→      return errorResponse(500, 'ANALYSIS_OUTPUT_INVALID', `LLM output does not match schema: ${llmValidation.errors!.join('; ')}`);
   127→    }
   128→
   129→    const llmData = llmValidation.data!;
   130→
   131→    // ─── 8. Calculate global score (canonical formula, SERVER-SIDE) ──
   132→    const analysis = llmData.analysis as AnalysisAxes;
   133→    const globalScore = calculateGlobalScore(analysis);
   134→
   135→    // ─── 9. Determine decision (canonical rules, SERVER-SIDE) ───
   136→    const decisionResult = determineDecision(
   137→      globalScore,
   138→      analysis,
   139→      llmData.decision.confidence_level
   140→    );
   141→
   142→    // ─── 10. Detect enrichment triggers ─────────────────────────
   143→    const enrichment = computeEnrichmentDecision(
   144→      analysis,
   145→      globalScore,
   146→      llmData.decision.confidence_level
   147→    );
   148→
   149→    // ─── 11. Determine inputs_used ──────────────────────────────
   150→    const inputsUsed: ('text' | 'voice' | 'link' | 'file')[] = [];
   151→    if (input.inputs.text) {
   152→      inputsUsed.push(input.inputs.text.source === 'voice_transcript' ? 'voice' : 'text');
   153→    }
   154→    if (input.inputs.links && input.inputs.links.length > 0) {
   155→      inputsUsed.push('link');
   156→    }
   157→    if (input.inputs.files && input.inputs.files.length > 0) {
   158→      inputsUsed.push('file');
   159→    }
   160→
   161→    // ─── 12. Assemble canonical output ──────────────────────────
   162→    const analysisId = crypto.randomUUID();
   163→
   164→    const output: AnalysisOutput = {
   165→      meta: {
   166→        schema_version: SCHEMA_VERSION,
   167→        analysis_id: analysisId,
   168→        timestamp: new Date().toISOString(),
   169→        orchestrator_version: `v${CURRENT_VERSION.replace('v', '')}`,
   170→        model: AI_MODEL,
   171→      },
   172→      idea: {
   173→        idea_id: input.idea.idea_id,
   174→        title: llmData.idea.title,
   175→        raw_summary: llmData.idea.raw_summary,
   176→        inputs_used: inputsUsed.length > 0 ? inputsUsed : ['text'],
   177→      },
   178→      analysis,
   179→      scores: {
   180→        global_score: globalScore,
   181→        weights: CANONICAL_WEIGHTS,
   182→      },
   183→      decision: {
   184→        recommendation: decisionResult.recommendation,
   185→        confidence_level: llmData.decision.confidence_level,
   186→        summary: llmData.decision.summary,
   187→      },
   188→      risks: llmData.risks as AnalysisOutput['risks'],
   189→      levers: llmData.levers as AnalysisOutput['levers'],
   190→      enrichment,
   191→      lab_orientation: llmData.lab_orientation as AnalysisOutput['lab_orientation'],
   192→    };
   193→
   194→    // ─── 13. Log for traceability ───────────────────────────────
   195→    const duration = Date.now() - startTime;
   196→    console.log(JSON.stringify({
   197→      event: 'analysis_complete',
   198→      request_id: input.meta.request_id,
   199→      analysis_id: analysisId,
   200→      prompt_version: CURRENT_VERSION,
   201→      model: AI_MODEL,
   202→      schema_version: SCHEMA_VERSION,
   203→      global_score: globalScore,
   204→      recommendation: decisionResult.recommendation,
   205→      enrichment_required: enrichment.required,
   206→      duration_ms: duration,
   207→      success: true,
   208→    }));
   209→
   210→    return NextResponse.json(output, { status: 200 });
   211→
   212→  } catch (error: unknown) {
   213→    const err = error as Error;
   214→    console.error('Unexpected analysis error:', err);
   215→    return errorResponse(500, 'INTERNAL_ERROR', `Unexpected error: ${err.message}`);
   216→  }
   217→}
   218→
   219→// ═══════════════════════════════════════════════════════════════════
   220→// ERROR HELPER
   221→// ═══════════════════════════════════════════════════════════════════
   222→
   223→function errorResponse(status: number, code: string, message: string): NextResponse<ApiError> {
   224→  return NextResponse.json(
   225→    {
   226→      error: {
   227→        code,
   228→        message,
   229→        details: { schema_version: SCHEMA_VERSION },
   230→      },
   231→    },
   232→    { status }
   233→  );
   234→}
