"use client";

import { useAuth } from "@/providers/auth-provider";
import { useLanguageStore } from "@/store/language-store";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { LogOut, Settings, Library, User as UserIcon } from "lucide-react";
import { useRouter } from "next/navigation";

export function UserNav() {
    const { user, signOut, setShowAuthModal } = useAuth();
    const { t } = useLanguageStore();
    const router = useRouter();

    if (!user) {
        return (
            <Button
                variant="ghost"
                onClick={() => setShowAuthModal(true)}
                className="rounded-lg text-gray-400 hover:text-white hover:bg-white/5 transition-all font-medium text-sm"
            >
                {t.auth.signIn}
            </Button>
        );
    }

    return (
        <DropdownMenu>
            <DropdownMenuTrigger asChild>
                <Button variant="ghost" className="relative h-10 w-10 rounded-full hover:bg-white/5 focus-visible:outline-none focus-visible:ring-0 transition-all overflow-hidden border-0">
                    <Avatar className="h-10 w-10 border-0">
                        <AvatarImage src={user.user_metadata?.avatar_url} alt={user.user_metadata?.full_name || user.email} className="object-cover" />
                        <AvatarFallback className="bg-[#F75105] text-white font-medium text-sm">
                            {user.email?.substring(0, 2).toUpperCase()}
                        </AvatarFallback>
                    </Avatar>
                </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent className="w-64 bg-[#2F323A] border-0 text-white rounded-xl shadow-2xl p-2 mt-2" align="end" forceMount>
                <DropdownMenuLabel className="font-normal p-3">
                    <div className="flex flex-col space-y-1.5">
                        <p className="text-sm font-medium leading-none text-white font-sans">{user.user_metadata?.full_name || "Utilisateur"}</p>
                        <p className="text-xs leading-none text-gray-400 font-sans">
                            {user.email}
                        </p>
                    </div>
                </DropdownMenuLabel>
                <DropdownMenuSeparator className="bg-[#3A3D45] my-1" />
                <DropdownMenuItem onClick={() => router.push("/workspace")} className="cursor-pointer hover:bg-[#3A3D45] focus:bg-[#3A3D45] rounded-lg px-3 py-2.5 transition-colors text-gray-200 focus:text-white">
                    <Library className="mr-3 h-4 w-4 text-[#F75105]" />
                    <span className="font-sans text-sm">{t.auth.library}</span>
                </DropdownMenuItem>
                <DropdownMenuItem className="cursor-pointer hover:bg-[#3A3D45] focus:bg-[#3A3D45] rounded-lg px-3 py-2.5 transition-colors text-gray-200 focus:text-white">
                    <Settings className="mr-3 h-4 w-4 text-gray-400" />
                    <span className="font-sans text-sm">{t.auth.settings}</span>
                </DropdownMenuItem>
                <DropdownMenuSeparator className="bg-[#3A3D45] my-1" />
                <DropdownMenuItem onClick={() => signOut()} className="cursor-pointer text-red-400 hover:text-red-300 hover:bg-red-500/10 focus:bg-red-500/10 rounded-lg px-3 py-2.5 transition-colors">
                    <LogOut className="mr-3 h-4 w-4" />
                    <span className="font-sans text-sm">{t.auth.logout}</span>
                </DropdownMenuItem>
            </DropdownMenuContent>
        </DropdownMenu>
    );
}

"use client";

import { useAuth } from "@/providers/auth-provider";
import { useLanguageStore } from "@/store/language-store";
import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Loader2, Lock, Mail } from "lucide-react";
import { cn } from "@/lib/utils";

export function AuthModal() {
    const { showAuthModal, setShowAuthModal, signIn, signUp, isLoading } = useAuth();
    const { t } = useLanguageStore();
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    const handleSignIn = async (e: React.FormEvent) => {
        e.preventDefault();
        await signIn(email, password);
    };

    const handleSignUp = async (e: React.FormEvent) => {
        e.preventDefault();
        await signUp(email, password);
    };

    return (
        <Dialog open={showAuthModal} onOpenChange={setShowAuthModal}>
            <DialogContent className="sm:max-w-[400px] p-0 overflow-hidden bg-background border-border text-foreground">
                {/* Background Effects - REMOVED per canonical design system */}

                <div className="p-8 relative z-10">
                    <DialogHeader className="mb-6 space-y-3">
                        <DialogTitle className="text-3xl font-sans font-bold text-center tracking-tighter">
                            k3rn.<span className="text-primary">labs</span>
                        </DialogTitle>
                        <DialogDescription className="text-center text-muted-foreground font-light text-base">
                            {t.auth.noAccount}
                        </DialogDescription>
                    </DialogHeader>

                    <Tabs defaultValue="signin" className="w-full">
                        <TabsList className="grid w-full grid-cols-2 mb-8 bg-secondary/50 border border-white/5 p-1 rounded-none">
                            <TabsTrigger
                                value="signin"
                                className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:transition-all duration-300 font-medium"
                            >
                                {t.auth.signIn}
                            </TabsTrigger>
                            <TabsTrigger
                                value="signup"
                                className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:transition-all duration-300 font-medium"
                            >
                                {t.auth.signUp}
                            </TabsTrigger>
                        </TabsList>

                        <TabsContent value="signin" className="animate-in slide-in-from-bottom-2 duration-300">
                            <form onSubmit={handleSignIn} className="space-y-5">
                                <div className="space-y-2">
                                    <Label htmlFor="email-in" className="text-xs font-mono uppercase tracking-wider text-muted-foreground ml-1">
                                        {t.auth.email}
                                    </Label>
                                    <div className="relative group">
                                        <Mail className="absolute left-3 top-3 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                                        <Input
                                            id="email-in"
                                            type="email"
                                            placeholder="agent@k3rn.labs"
                                            value={email}
                                            onChange={(e) => setEmail(e.target.value)}
                                            className="pl-10 h-11 bg-secondary/30 border-white/10 focus:border-primary/50 focus:ring-primary/20 transition-all font-light"
                                            required
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="password-in" className="text-xs font-mono uppercase tracking-wider text-muted-foreground ml-1">
                                        {t.auth.password}
                                    </Label>
                                    <div className="relative group">
