"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { ArrowRight } from "lucide-react";
import { K3rnLogo } from "@/components/ui/k3rn-logo";
import { LanguageSelector } from "@/components/ui/language-selector";
import { UserNav } from "@/components/layout/user-nav";
import { cn } from "@/lib/utils";

const APP_NAV_LINKS = [
    { label: "Capture", href: "/capture" },
    { label: "Dossiers", href: "/workspace" },
];

interface SiteHeaderProps {
    variant?: "public" | "app";
    className?: string;
}

export function SiteHeader({ variant = "public", className }: SiteHeaderProps) {
    const pathname = usePathname();
    const isApp = variant === "app";

    return (
        <header
            className={cn(
                "sticky top-0 z-50 w-full border-b border-[--color-border-subtle] bg-[#22242B]/90 backdrop-blur-xl saturate-[1.2] supports-[backdrop-filter]:bg-[#22242B]/70 transition-all duration-300",
                className
            )}
        >
            <div className="max-w-7xl mx-auto flex h-16 items-center justify-between px-6">
                {/* Left: Brand + Nav */}
                <div className="flex items-center gap-6">
                    <Link
                        href={isApp ? "/workspace" : "/"}
                        className="flex items-center gap-2 transition-opacity hover:opacity-80 group cursor-pointer"
                    >
                        <K3rnLogo size="sm" className={cn("transition-transform duration-500 group-hover:rotate-180", !isApp && "brightness-150")} />
                    </Link>

                    {isApp && (
                        <>
                            <div className="h-5 w-[1px] bg-[--color-border-default]" />
                            <nav className="hidden md:flex items-center gap-6">
                                {APP_NAV_LINKS.map((link) => {
                                    const isActive = pathname === link.href || pathname?.startsWith(link.href + "/");
                                    return (
                                        <Link
                                            key={link.href}
                                            href={link.href}
                                            className={cn(
                                                "relative text-sm font-medium uppercase tracking-widest transition-colors duration-200 cursor-pointer pb-[1.19rem] pt-[1.19rem]",
                                                isActive
                                                    ? "text-[#F75105]"
                                                    : "text-[#A1A1AA] hover:text-[#FAFAFA]"
                                            )}
                                        >
                                            {link.label}
                                            {isActive && (
                                                <span className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#F75105]" />
                                            )}
                                        </Link>
                                    );
                                })}
                            </nav>
                        </>
                    )}
                </div>

                {/* Right: Controls */}
                <div className="flex items-center gap-6">
                    {variant === "public" ? (
                        <>
                            <nav className="hidden md:flex items-center gap-8">
                                {["Manifesto", "Technologie", "Sécurité"].map((item) => (
                                    <Link
                                        key={item}
                                        href={`#${item.toLowerCase()}`}
                                        className="text-xs font-mono font-medium uppercase tracking-widest text-[#94A3B8] hover:text-white transition-colors duration-200 cursor-pointer"
                                    >
                                        {item}
                                    </Link>
                                ))}
                            </nav>
                            <Link href="/capture" className="cursor-pointer">
                                <button className="group flex items-center gap-2 bg-[#F75105] hover:bg-[#F75105]/90 text-white px-5 py-2 rounded-full text-xs font-bold uppercase tracking-wider transition-all duration-300 shadow-[0_0_20px_rgba(247,81,5,0.2)] hover:shadow-[0_0_30px_rgba(247,81,5,0.4)] hover:scale-105 active:scale-95 cursor-pointer">
                                    Commencer
                                    <ArrowRight className="w-3 h-3 group-hover:translate-x-1 transition-transform duration-200" />
                                </button>
                            </Link>
                        </>
                    ) : (
                        <div className="flex items-center gap-3">
                            <LanguageSelector />
                            <div className="h-4 w-[1px] bg-[--color-border-default] mx-2" />
                            <UserNav />
                        </div>
                    )}
                </div>
            </div>
        </header>
    );
}

