### Step 3: `useProfile` Hook

**File to create**: `/Users/user/Desktop/K3rn.labas_test/k3rn-platform/src/hooks/use-profile.ts`

**Design decision**: Use a plain React hook with `useState`/`useEffect` rather than Zustand. Rationale: The existing app-wide state patterns (auth, language) both use React Context, not Zustand. Zustand is only used in the isolated logo-generator feature. To stay consistent with the project conventions, a React hook that depends on the existing `useAuth()` context is the right approach. If multiple components need the profile, the hook can be called in each -- Supabase's client-side query caching and the fact that the hook only fetches once per user session (with local state) keep this efficient.

```typescript
"use client";

import { useState, useEffect, useCallback } from "react";
import { useAuth } from "@/providers/auth-provider";
import { createClient } from "@/lib/supabase/client";
import type { Profile, ProfileUpdate } from "@/lib/types/profile";

export function useProfile() {
  const { user } = useAuth();
  const [profile, setProfile] = useState<Profile | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const supabase = createClient();

  // Fetch profile when user changes
  useEffect(() => {
    if (!user) {
      setProfile(null);
      setIsLoading(false);
      return;
    }

    const fetchProfile = async () => {
      setIsLoading(true);
      const { data, error } = await supabase
        .from("profiles")
        .select("*")
        .eq("id", user.id)
        .single();

      if (error && error.code !== "PGRST116") {
        // PGRST116 = no rows found (profile not created yet)
        console.error("Profile fetch error:", error);
      }
      setProfile(data ?? null);
      setIsLoading(false);
    };

    fetchProfile();
  }, [user, supabase]);

  const createProfile = useCallback(
    async (profileData: ProfileUpdate) => {
      if (!user) throw new Error("Not authenticated");
      const { data, error } = await supabase
        .from("profiles")
        .insert({ id: user.id, ...profileData })
        .select()
        .single();
      if (error) throw error;
      setProfile(data);
      return data;
    },
    [user, supabase]
  );

  const updateProfile = useCallback(
    async (updates: Partial<ProfileUpdate>) => {
      if (!user) throw new Error("Not authenticated");
      const { data, error } = await supabase
        .from("profiles")
        .update(updates)
        .eq("id", user.id)
        .select()
        .single();
      if (error) throw error;
      setProfile(data);
      return data;
    },
    [user, supabase]
  );

  return { profile, isLoading, createProfile, updateProfile };
}
```

**Key details**:
- The `PGRST116` error code check handles the case where a user exists but no profile row has been created yet (graceful degradation).
- `createProfile` is used after sign-up. `updateProfile` is used from the settings page.
- Both `createProfile` and `updateProfile` call `.select().single()` to return the updated row and sync local state.
- The hook is re-entrant -- calling it from multiple components is fine because each creates its own local state. For an optimization path in the future, this could be promoted to a React Context or a Zustand store with `persist` middleware.

