   ```typescript
   const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
     setSession(session);
     setUser(session?.user ?? null);
     setIsLoading(false);

     if (session) {
       setShowAuthModal(false);

       // Auto-create profile if it doesn't exist
       const { data: existingProfile } = await supabase
         .from("profiles")
         .select("id")
         .eq("id", session.user.id)
         .single();

       if (!existingProfile) {
         const meta = session.user.user_metadata;
         await supabase.from("profiles").insert({
           id: session.user.id,
           display_name: meta?.display_name || null,
           entity_type: meta?.entity_type || 'individual',
           lab_name: meta?.lab_name || null,
         });
       }
     }
   });
   ```

**Why this approach**: It handles both the immediate-confirmation case and the email-confirmation case. When the user eventually confirms their email and signs in, the `SIGNED_IN` event fires, and the profile is created with the metadata stored at sign-up time. It also handles users who signed up before the profiles feature existed (they get a profile with null display_name on their next login).

