"use client";

import React, { createContext, useContext, useState, useEffect } from "react";
import { toast } from "sonner";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { User, Session } from "@supabase/supabase-js";

interface AuthContextType {
    user: User | null;
    session: Session | null;
    isLoading: boolean;
    signIn: (email: string, password?: string) => Promise<void>;
    signUp: (email: string, password?: string) => Promise<void>;
    signOut: () => Promise<void>;
    showAuthModal: boolean;
    setShowAuthModal: (show: boolean) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
    const [user, setUser] = useState<User | null>(null);
    const [session, setSession] = useState<Session | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [showAuthModal, setShowAuthModal] = useState(false);
    const router = useRouter();
    const supabase = createClient();

    // Initialize Auth State
    useEffect(() => {
        const initAuth = async () => {
            try {
                const { data: { session } } = await supabase.auth.getSession();
                setSession(session);
                setUser(session?.user ?? null);
            } catch (error) {
                console.error("Auth init error:", error);
            } finally {
                setIsLoading(false);
            }
        };

        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setSession(session);
            setUser(session?.user ?? null);
            setIsLoading(false);

            if (session) {
                // Close modal on successful sign in if open
                setShowAuthModal(false);
            }
        });

        initAuth();

        return () => subscription.unsubscribe();
    }, [supabase]);

    const signIn = async (email: string, password?: string) => {
        try {
            setIsLoading(true);

            if (password) {
                // Email + Password
                const { error } = await supabase.auth.signInWithPassword({
                    email,
                    password
                });
                if (error) throw error;
                toast.success("Bon retour", { description: "Connexion réussie." });
            } else {
                // Magic Link (Fallback)
                const { error } = await supabase.auth.signInWithOtp({
                    email,
                    options: {
                        emailRedirectTo: `${window.location.origin}/auth/callback`,
                    },
                });
                if (error) throw error;
                toast.success("Lien de connexion envoyé", { description: "Vérifiez votre boîte mail." });
            }
            setShowAuthModal(false);
        } catch (error: any) {
            console.error("Login error:", error);
            toast.error("Erreur de connexion", { description: error.message || "Identifiants invalides." });
        } finally {
            setIsLoading(false);
        }
    };

    const signUp = async (email: string, password?: string) => {
        try {
            setIsLoading(true);

            if (password) {
                const { error } = await supabase.auth.signUp({
                    email,
                    password,
                    options: {
                        emailRedirectTo: `${window.location.origin}/auth/callback`,
                    }
                });
                if (error) throw error;
                toast.success("Compte créé", { description: "Vérifiez votre email pour confirmer." });
            } else {
                const { error } = await supabase.auth.signInWithOtp({
                    email,
                    options: {
                        emailRedirectTo: `${window.location.origin}/auth/callback`,
                    }
                });
                if (error) throw error;
                toast.success("Vérifiez votre email", { description: "Un lien de connexion a été envoyé." });
            }
            setShowAuthModal(false);
        } catch (error: any) {
            console.error("Signup error:", error);
            toast.error("Erreur d'inscription", { description: error.message });
        } finally {
            setIsLoading(false);
        }
    };

    const signOut = async () => {
        try {
            setIsLoading(true);
            await supabase.auth.signOut();
            toast.info("Déconnecté");
            router.push("/");
            router.refresh();
        } catch (error) {
            console.error("SignOut error:", error);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <AuthContext.Provider value={{
            user,
            session,
            isLoading,
            signIn,
            signUp,
            signOut,
            showAuthModal,
            setShowAuthModal
        }}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error("useAuth must be used within an AuthProvider");
    }
    return context;
}

