"use client";

import { useAuth } from "@/providers/auth-provider";
import { useLanguageStore } from "@/store/language-store";
import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Loader2, Lock, Mail } from "lucide-react";
import { cn } from "@/lib/utils";

export function AuthModal() {
    const { showAuthModal, setShowAuthModal, signIn, signUp, isLoading } = useAuth();
    const { t } = useLanguageStore();
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    const handleSignIn = async (e: React.FormEvent) => {
        e.preventDefault();
        await signIn(email, password);
    };

    const handleSignUp = async (e: React.FormEvent) => {
        e.preventDefault();
        await signUp(email, password);
    };

    return (
        <Dialog open={showAuthModal} onOpenChange={setShowAuthModal}>
            <DialogContent className="sm:max-w-[400px] p-0 overflow-hidden bg-background border-border text-foreground">
                {/* Background Effects - REMOVED per canonical design system */}

                <div className="p-8 relative z-10">
                    <DialogHeader className="mb-6 space-y-3">
                        <DialogTitle className="text-3xl font-sans font-bold text-center tracking-tighter">
                            k3rn.<span className="text-primary">labs</span>
                        </DialogTitle>
                        <DialogDescription className="text-center text-muted-foreground font-light text-base">
                            {t.auth.noAccount}
                        </DialogDescription>
                    </DialogHeader>

                    <Tabs defaultValue="signin" className="w-full">
                        <TabsList className="grid w-full grid-cols-2 mb-8 bg-secondary/50 border border-white/5 p-1 rounded-none">
                            <TabsTrigger
                                value="signin"
                                className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:transition-all duration-300 font-medium"
                            >
                                {t.auth.signIn}
                            </TabsTrigger>
                            <TabsTrigger
                                value="signup"
                                className="data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:transition-all duration-300 font-medium"
                            >
                                {t.auth.signUp}
                            </TabsTrigger>
                        </TabsList>

                        <TabsContent value="signin" className="animate-in slide-in-from-bottom-2 duration-300">
                            <form onSubmit={handleSignIn} className="space-y-5">
                                <div className="space-y-2">
                                    <Label htmlFor="email-in" className="text-xs font-mono uppercase tracking-wider text-muted-foreground ml-1">
                                        {t.auth.email}
                                    </Label>
                                    <div className="relative group">
                                        <Mail className="absolute left-3 top-3 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                                        <Input
                                            id="email-in"
                                            type="email"
                                            placeholder="agent@k3rn.labs"
                                            value={email}
                                            onChange={(e) => setEmail(e.target.value)}
                                            className="pl-10 h-11 bg-secondary/30 border-white/10 focus:border-primary/50 focus:ring-primary/20 transition-all font-light"
                                            required
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="password-in" className="text-xs font-mono uppercase tracking-wider text-muted-foreground ml-1">
                                        {t.auth.password}
                                    </Label>
                                    <div className="relative group">
                                        <Lock className="absolute left-3 top-3 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
                                        <Input
                                            id="password-in"
                                            type="password"
                                            value={password}
                                            onChange={(e) => setPassword(e.target.value)}
                                            className="pl-10 h-11 bg-secondary/30 border-white/10 focus:border-primary/50 focus:ring-primary/20 transition-all font-light"
                                            required
                                        />
                                    </div>
                                </div>
                                <Button
                                    type="submit"
                                    className="w-full h-11 bg-primary text-black font-bold tracking-wide hover:bg-primary/90 transition-all mt-4"
                                    disabled={isLoading}
                                >
                                    {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : t.auth.signIn}
                                </Button>
                            </form>
                        </TabsContent>

