                <DropdownMenuSeparator className="bg-[#3A3D45] my-1" />
                <DropdownMenuItem onClick={() => signOut()} className="cursor-pointer text-red-400 hover:text-red-300 hover:bg-red-500/10 focus:bg-red-500/10 rounded-lg px-3 py-2.5 transition-colors">
