@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-sans);
  --font-mono: var(--font-jetbrains-mono);

  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);

  --radius-sm: var(--radius-sm);
  --radius-md: var(--radius-md);
  --radius-lg: var(--radius-lg);
  --radius-xl: var(--radius-xl);
  --radius-2xl: var(--radius-2xl);
}

/*
  ═══════════════════════════════════════════════════════════════════════════
  K3RN.LABS DESIGN SYSTEM — Dark 900 Canvas
  ═══════════════════════════════════════════════════════════════════════

  Depth architecture (cool blue undertone):
    L0  Canvas     #22242B  — page background
    L-1 Recessed   #1A1C22  — inputs, insets, radar
    L1  Card       #2C2F38  — elevated cards, dialogs
    L2  Card Hover #363940  — interactive surfaces
    L3  Surface    #464950  — buttons, controls, dock elements
    L4  Surface Hi #62656D  — muted interactive, scrollbar
*/

:root {
  /* ═══════════════════════════════════════════════════════════════════════
     RADIUS TOKENS — "Modern Rounded" (Official Canonical)
     ═══════════════════════════════════════════════════════════════════════ */
  --radius: 0.5rem;
  /* Base reference */
  --radius-sm: 0.375rem;
  /* 6px */
  --radius-md: 0.5rem;
  /* 8px */
  --radius-lg: 0.75rem;
  /* 12px */
  --radius-xl: 1rem;
  /* 16px */
  --radius-2xl: 1.5rem;
  /* 24px - STANDARD CARD RADIUS */
  --radius-full: 9999px;

  /* ═══════════════════════════════════════════════════════════════════════
     DARK 900 CANVAS — Elevation Layers
     ═══════════════════════════════════════════════════════════════════════ */
  --color-bg-primary: #22242B;
  /* L0 Canvas — Page Background */
  --color-bg-secondary: #1A1C22;
  /* L-1 Recessed — Inputs, insets */
  --color-bg-card: #2C2F38;
  /* L1 Card — Elevated surfaces */
  --color-bg-card-hover: #363940;
  /* L2 Card Hover — Interactive */

  /* ═══════════════════════════════════════════════════════════════════════
     SURFACES & BORDERS
     ═══════════════════════════════════════════════════════════════════════ */
  --color-surface-1: #464950;
  /* L3 Surface */
  --color-surface-2: #62656D;
  /* L4 Surface Hi */

  --color-border-subtle: rgba(255, 255, 255, 0.06);
  --color-border-default: rgba(255, 255, 255, 0.10);
  --color-border-strong: rgba(255, 255, 255, 0.18);

  /* ═══════════════════════════════════════════════════════════════════════
     TEXT
     ═══════════════════════════════════════════════════════════════════════ */
  --color-text-primary: #F5F5F7;
  /* Headings, Strong text */
  --color-text-secondary: #A0A3AB;
  /* Body text */
  --color-text-muted: #6C6F78;
  /* Muted text */

  /* ═══════════════════════════════════════════════════════════════════════
     BRAND
     ═══════════════════════════════════════════════════════════════════════ */
  --color-brand-primary: #F75105;
  /* K3RN Orange */
  --color-brand-secondary: #F78E21;
  /* Lighter Orange */

  /* ═══════════════════════════════════════════════════════════════════════
     SHADOW TOKENS
     ═══════════════════════════════════════════════════════════════════════ */
  --shadow-sm: 0 1px 2px rgb(0 0 0 / 0.05);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.3);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.4);
  --shadow-glow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  --shadow-soft: 0 2px 4px -1px rgba(0, 0, 0, 0.05);
  --shadow-elevation: 0 8px 32px rgba(0, 0, 0, 0.5);

  /* ═══════════════════════════════════════════════════════════════════════
     DECISION PALETTE
     ═══════════════════════════════════════════════════════════════════════ */
  --color-go: #22C55E;
  --color-explore: #F59E0B;
  --color-park: #6B7280;
  --color-kill: #EF4444;

  /* ═══════════════════════════════════════════════════════════════════════
     SHADCN COMPATIBILITY LAYER
     ═══════════════════════════════════════════════════════════════════════ */
  --background: var(--color-bg-primary);
  --foreground: var(--color-text-secondary);

  --card: var(--color-bg-card);
  --card-foreground: var(--color-text-secondary);

  --popover: var(--color-bg-secondary);
  --popover-foreground: var(--color-text-secondary);

  --primary: var(--color-brand-primary);
  --primary-foreground: #FFFFFF;

  --secondary: var(--color-surface-1);
  --secondary-foreground: var(--color-text-secondary);

  --muted: var(--color-bg-secondary);
  --muted-foreground: var(--color-text-muted);

  --accent: var(--color-surface-1);
  --accent-foreground: var(--color-text-primary);

  --destructive: 0 84.2% 60.2%;
  --destructive-foreground: 0 0% 98%;

  --border: var(--color-border-default);
  --input: var(--color-bg-secondary);
  --ring: var(--color-brand-primary);

  /* Chart colors */
  --chart-1: var(--color-brand-primary);
  --chart-2: var(--color-brand-secondary);
  --chart-3: #6C6F78;
  --chart-4: #464950;
  --chart-5: #22242B;

  /* Sidebar tokens */
  --sidebar: var(--color-bg-secondary);
  --sidebar-foreground: var(--color-text-secondary);
  --sidebar-primary: var(--color-brand-primary);
  --sidebar-primary-foreground: #FFFFFF;
  --sidebar-accent: var(--color-surface-1);
  --sidebar-accent-foreground: var(--color-text-primary);
  --sidebar-border: var(--color-border-default);
  --sidebar-ring: var(--color-brand-primary);
}

/* Dark mode class — ensures consistency */
.dark {
  --background: var(--color-bg-primary);
  --foreground: var(--color-text-secondary);
  --card: var(--color-bg-card);
  --card-foreground: var(--color-text-secondary);
  --popover: var(--color-bg-secondary);
  --popover-foreground: var(--color-text-secondary);
  --primary: var(--color-brand-primary);
  --primary-foreground: #FFFFFF;
  --secondary: var(--color-surface-1);
  --secondary-foreground: var(--color-text-secondary);
  --muted: var(--color-bg-secondary);
  --muted-foreground: var(--color-text-muted);
  --accent: var(--color-surface-1);
  --accent-foreground: var(--color-text-primary);
  --destructive: 0 84.2% 60.2%;
  --destructive-foreground: 0 0% 98%;
  --border: var(--color-border-default);
  --input: var(--color-bg-secondary);
  --ring: var(--color-brand-primary);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }

  body {
    @apply bg-background text-foreground antialiased selection:bg-[#F75105]/30 selection:text-white;
    font-feature-settings: "rlig" 1, "calt" 1;
    position: relative;
  }

  /* Canvas dot-grid pattern */
  body::before {
    content: '';
    position: fixed;
    inset: 0;
    z-index: 0;
    pointer-events: none;
    background-image: radial-gradient(rgba(255, 255, 255, 0.035) 1px, transparent 1px);
    background-size: 24px 24px;
  }
}

@layer utilities {
  .shadow-glow {
    box-shadow: var(--shadow-glow);
  }

  .shadow-soft {
    box-shadow: var(--shadow-soft);
  }

  .shadow-elevation {
    box-shadow: var(--shadow-elevation);
  }
}

@keyframes spin-rhythm {
  0% { transform: rotate(0deg); }
  15% { transform: rotate(180deg); }
  50% { transform: rotate(180deg); }
  65% { transform: rotate(360deg); }
  100% { transform: rotate(360deg); }
}

