file.content:
  line-height: 1;
  letter-spacing: 0.05em;
  margin-bottom: var(--space-8);
}

.hero-title .brand-name {
  font-weight: 700;
}

.hero-subtitle {
  font-size: 1.25rem;
  color: var(--text-secondary);
  max-width: 700px;
  margin: 0 auto var(--space-12);
  line-height: 1.6;
  font-weight: 300;
}

/* Section */
.section {
  padding: var(--space-20) 0;
  border-top: 1px solid var(--border-subtle);
}

.section-header {
  margin-bottom: var(--space-12);
}

.section-number {
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--brand-primary);
  margin-bottom: var(--space-3);
}

.section-title {
  font-size: 3rem;
  font-weight: 300;
  line-height: 1.1;
  margin-bottom: var(--space-4);
}

.section-description {
  font-size: 1.125rem;
  color: var(--text-secondary);
  max-width: 800px;
  line-height: 1.6;
  font-weight: 300;
}

/* Grid */
.grid {
  display: grid;
  gap: var(--space-6);
}

.grid-2 {
  grid-template-columns: repeat(2, 1fr);
}

.grid-3 {
  grid-template-columns: repeat(3, 1fr);
}

.grid-4 {
  grid-template-columns: repeat(4, 1fr);
}

/* Card */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-2xl);
  padding: var(--space-8);
  transition: all 0.3s ease;
}

.card:hover {
  border-color: var(--border-strong);
  background: var(--bg-card-hover);
}

.card-title {
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: var(--space-3);
}

.card-description {
  font-size: 0.875rem;
  color: var(--text-secondary);
  line-height: 1.6;
}

/* Logo Showcase */
.logo-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--space-8);
  margin-top: var(--space-12);
}

.logo-display {
  background: var(--bg-card);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-2xl);
  padding: var(--space-16);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 400px;
  position: relative;
}

.logo-display.light {
  background: var(--neutral-lightest);
}

.logo-label {
  position: absolute;
  top: var(--space-6);
  left: var(--space-6);
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--text-muted);
}

.logo-display.light .logo-label {
  color: var(--neutral-dark-700);
}

.logo-svg {
  max-width: 400px;
  width: 100%;
  height: auto;
}

.logo-svg-small {
  max-width: 200px;
  width: 100%;
  height: auto;
}

/* Color Palette */
.color-grid {
  display: grid;
  gap: var(--space-8);
  margin-top: var(--space-12);
}

.color-group {
  background: var(--bg-card);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-2xl);
  overflow: hidden;
}

.color-group-header {
  padding: var(--space-6);
  border-bottom: 1px solid var(--border-default);
}

.color-group-title {
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: var(--space-2);
}

.color-swatches {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
}

.color-swatch {
  padding: var(--space-12) var(--space-6);
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  gap: var(--space-2);
  min-height: 180px;
  border-right: 1px solid var(--border-subtle);
}

.color-swatch:last-child {
  border-right: none;
}

.color-name {
  font-size: 0.875rem;
  font-weight: 600;
}

.color-value {
  font-family: 'Courier New', monospace;
  font-size: 0.75rem;

