  border-radius: var(--radius-md);
}

.type-meta {
  font-size: 0.75rem;
  color: var(--text-muted);
  font-family: 'Courier New', monospace;
  margin-top: var(--space-2);
}

/* Components */
.component-showcase {
  display: grid;
  gap: var(--space-8);
  margin-top: var(--space-12);
}

.component-demo {
  background: var(--bg-card);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-2xl);
  overflow: hidden;
}

.component-header {
  padding: var(--space-6);
  border-bottom: 1px solid var(--border-default);
}

.component-title {
  font-size: 1.25rem;
  font-weight: 600;
}

.component-preview {
  padding: var(--space-12);
  background: var(--bg-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 250px;
}

/* Button */
.btn {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-6);
  font-size: 0.875rem;
  font-weight: 600;
  border-radius: var(--radius-md);
  border: none;
  cursor: pointer;
  transition: all 0.2s;
  text-decoration: none;
  font-family: 'Inter', sans-serif;
}

.btn-primary {
  background: var(--brand-primary);
  color: white;
}

.btn-primary:hover {
  background: var(--brand-secondary);
  box-shadow: var(--shadow-glow);
  transform: translateY(-1px);
}

.btn-secondary {
  background: transparent;
  color: var(--text-primary);
  border: 1px solid var(--border-default);
}

.btn-secondary:hover {
  background: var(--bg-card);
  border-color: var(--border-strong);
}

.btn-lg {
  padding: var(--space-4) var(--space-8);
  font-size: 1rem;
}

/* Input */
.input {
  width: 100%;
  padding: var(--space-3) var(--space-4);
  background: var(--bg-secondary);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-md);
  color: var(--text-primary);
  font-size: 0.875rem;
  font-family: 'Inter', sans-serif;
  transition: all 0.2s;
}

.input:focus {
  outline: none;
  border-color: var(--brand-primary);
  box-shadow: 0 0 0 3px rgba(247, 81, 5, 0.1);
}

.input::placeholder {
  color: var(--text-muted);
}

/* Icon Grid */
.icon-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--space-6);
  margin-top: var(--space-8);
}

.icon-display {
  background: var(--bg-card);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-xl);
  padding: var(--space-8);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-4);
  min-height: 250px;
  justify-content: center;
  transition: all 0.3s;
}

.icon-display:hover {
  border-color: var(--brand-primary);
  transform: translateY(-4px);
}

.icon-visual {
  width: auto;
  height: auto;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.icon-shape {
  width: 60px;
  height: 70px;
  background: linear-gradient(135deg, var(--neutral-dark-700) 0%, var(--neutral-light-300) 100%);
  border-radius: 40% 60% 30% 70% / 50% 40% 60% 50%;
  position: relative;
}

.icon-accent {
  width: 24px;
  height: 24px;
  background: var(--brand-primary);
  border-radius: 50%;
  position: absolute;
  top: -5px;
  right: 10px;
  box-shadow: var(--shadow-glow);
}

.icon-name {
  font-size: 0.875rem;
  color: var(--text-secondary);
  text-align: center;
}

/* Guidelines */
.guideline-card {
  background: var(--bg-card);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-2xl);
  padding: var(--space-8);
  margin-bottom: var(--space-6);
}

.guideline-header {
  display: flex;
  align-items: flex-start;
  gap: var(--space-4);
  margin-bottom: var(--space-6);
}

.guideline-icon {
  width: 48px;
  height: 48px;
  background: rgba(247, 81, 5, 0.1);
  border-radius: var(--radius-lg);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  flex-shrink: 0;
}

.guideline-title {
  font-size: 1.5rem;
  font-weight: 600;
  margin-bottom: var(--space-2);
}

.guideline-list {
  list-style: none;
  display: grid;
  gap: var(--space-3);
}

.guideline-list li {
  display: flex;
  gap: var(--space-3);
  color: var(--text-secondary);
  line-height: 1.6;
  padding-left: var(--space-6);
  position: relative;
}

.guideline-list li::before {
  content: '→';
  color: var(--brand-primary);
  font-weight: 600;
  position: absolute;
  left: 0;
}

/* Do/Don't */
.examples {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--space-8);
  margin-top: var(--space-12);
}

.example {
  background: var(--bg-card);
  border: 2px solid var(--border-default);
  border-radius: var(--radius-2xl);
  overflow: hidden;
}

.example.do {
  border-color: #22C55E;
}

.example.dont {
  border-color: #EF4444;
}

.example-preview {
  background: var(--bg-secondary);
  padding: var(--space-12);

