"use client";

import { useState, useEffect } from "react";
import { SiteHeader } from "@/components/layout/site-header";
import { useProfile } from "@/hooks/use-profile";
import { useAuth } from "@/providers/auth-provider";
import { useLanguageStore } from "@/store/language-store";
import { useRouter } from "next/navigation";
import { Loader2, User, FlaskConical } from "lucide-react";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

export default function SettingsPage() {
    const router = useRouter();
    const { user, isLoading: authLoading } = useAuth();
    const { t } = useLanguageStore();
    const { profile, updateProfile, createProfile } = useProfile();

    const [displayName, setDisplayName] = useState("");
    const [entityType, setEntityType] = useState<"individual" | "company">("individual");
    const [labName, setLabName] = useState("");
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (!authLoading && !user) router.push("/");
    }, [user, authLoading, router]);

    useEffect(() => {
        if (profile) {
            setDisplayName(profile.display_name || "");
            setEntityType(profile.entity_type || "individual");
            setLabName(profile.lab_name || "");
        }
    }, [profile]);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        try {
            const data = { display_name: displayName, entity_type: entityType, lab_name: labName };
            if (profile) {
                await updateProfile(data);
            } else {
                await createProfile(data);
            }
            toast.success(t.settings.saved);
        } catch (error: any) {
            toast.error(t.settings.error, { description: error.message });
        } finally {
            setIsSaving(false);
        }
    };

    if (authLoading) {
        return (
            <div className="min-h-screen bg-background text-foreground font-sans">
                <SiteHeader variant="app" />
                <main className="pt-12 pb-40 px-8 w-full max-w-[800px] mx-auto flex items-center justify-center">
                    <Loader2 className="w-6 h-6 animate-spin text-[--color-text-muted]" />
                </main>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[--color-brand-primary]/30 flex flex-col overflow-x-hidden">
            <SiteHeader variant="app" />

            <main className="relative z-[1] flex-1 pt-12 pb-40 px-8 w-full max-w-[800px] mx-auto">

                {/* Page heading — same register as workspace welcome */}
                <div className="mb-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <h1 className="text-[2.5rem] font-light text-white tracking-[-0.02em] leading-[1.1] mb-3">
                        {t.settings.title}
                    </h1>
                    <p className="text-base text-[--color-text-muted]">
                        {t.settings.subtitle}
                    </p>
                </div>

                {/* Form card — brand book card spec */}
                <div
                    className="animate-in fade-in slide-in-from-bottom-4 duration-500 transition-all duration-300"
                    style={{
                        background: "var(--color-bg-card)",
                        border: "1px solid var(--color-border-default)",
                        borderRadius: "var(--radius-2xl)",
                        padding: "var(--space-8)",
                    }}
                >
                    <form onSubmit={handleSave}>

                        {/* Display Name */}
                        <div className="mb-6">
                            <label
                                htmlFor="settings-display-name"
                                className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3"
                            >
                                {t.auth.displayName}
                            </label>
                            <div className="relative group">
                                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[--color-text-muted] group-focus-within:text-[--color-brand-primary] transition-colors" />
                                <input
                                    id="settings-display-name"
                                    type="text"
                                    placeholder={t.settings.displayNamePlaceholder}
                                    value={displayName}
                                    onChange={(e) => setDisplayName(e.target.value)}
                                    className="w-full pl-11 pr-4 py-3 text-sm bg-[--color-bg-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-[--color-text-primary] placeholder:text-[--color-text-muted] font-normal outline-none transition-all focus:border-[--color-brand-primary] focus:shadow-[0_0_0_3px_rgba(247,81,5,0.1)]"
                                />
                            </div>
                        </div>

                        {/* Entity Type */}
                        <div className="mb-6">
                            <label className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3">
                                {t.auth.entityType}
                            </label>
                            <div className="grid grid-cols-2 gap-3">
                                <button
                                    type="button"
                                    onClick={() => setEntityType("individual")}
                                    className={cn(
                                        "py-3 text-sm font-semibold rounded-[var(--radius-md)] transition-all duration-200 cursor-pointer",
                                        entityType === "individual"
                                            ? "bg-[--color-brand-primary] text-white"
                                            : "bg-transparent text-[--color-text-primary] border border-[--color-border-default] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]"
                                    )}
                                >
                                    {t.auth.entityIndividual}
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setEntityType("company")}
                                    className={cn(
                                        "py-3 text-sm font-semibold rounded-[var(--radius-md)] transition-all duration-200 cursor-pointer",
                                        entityType === "company"
                                            ? "bg-[--color-brand-primary] text-white"
                                            : "bg-transparent text-[--color-text-primary] border border-[--color-border-default] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]"
                                    )}
                                >
                                    {t.auth.entityCompany}
                                </button>
                            </div>
                        </div>

                        {/* Lab Name */}
                        <div className="mb-8">
                            <label
                                htmlFor="settings-lab-name"
                                className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3"
                            >
                                {t.auth.labName}
                            </label>
                            <div className="relative group">
                                <FlaskConical className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[--color-text-muted] group-focus-within:text-[--color-brand-primary] transition-colors" />
                                <input
                                    id="settings-lab-name"
                                    type="text"
                                    placeholder={t.settings.labNamePlaceholder}
                                    value={labName}
                                    onChange={(e) => setLabName(e.target.value)}
                                    className="w-full pl-11 pr-4 py-3 text-sm bg-[--color-bg-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-[--color-text-primary] placeholder:text-[--color-text-muted] font-normal outline-none transition-all focus:border-[--color-brand-primary] focus:shadow-[0_0_0_3px_rgba(247,81,5,0.1)]"
                                />
                            </div>
                        </div>

                        {/* Save */}
                        <button
                            type="submit"
                            disabled={isSaving}
                            className={cn(
                                "inline-flex items-center gap-2 py-3 px-6 text-sm font-semibold rounded-[var(--radius-md)] transition-all duration-200 cursor-pointer",
                                isSaving
                                    ? "bg-[--color-brand-primary]/50 text-white/50 cursor-not-allowed"
                                    : "bg-[--color-brand-primary] text-white hover:bg-[--color-brand-secondary] hover:shadow-[0_0_30px_rgba(247,81,5,0.3)] hover:-translate-y-[1px]"
                            )}
                        >
                            {isSaving && <Loader2 className="w-4 h-4 animate-spin" />}
                            {isSaving ? t.settings.saving : t.settings.save}
                        </button>
                    </form>
                </div>
            </main>
        </div>
    );
}

