    18→
    19→    const [displayName, setDisplayName] = useState("");
    20→    const [entityType, setEntityType] = useState<"individual" | "company">("individual");
    21→    const [labName, setLabName] = useState("");
    22→    const [isSaving, setIsSaving] = useState(false);
    23→
    24→    useEffect(() => {
    25→        if (!authLoading && !user) router.push("/");
    26→    }, [user, authLoading, router]);
    27→
    28→    useEffect(() => {
