                    <form onSubmit={handleSave}>

                        {/* Display Name */}
                        <div className="mb-6">
                            <label
                                htmlFor="settings-display-name"
                                className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3"
                            >
                                {t.auth.displayName}
                            </label>
                            <div className="relative group">
                                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[--color-text-muted] group-focus-within:text-[--color-brand-primary] transition-colors" />
                                <input
                                    id="settings-display-name"
                                    type="text"
                                    placeholder={t.settings.displayNamePlaceholder}
                                    value={displayName}
                                    onChange={(e) => setDisplayName(e.target.value)}
                                    className="w-full pl-11 pr-4 py-3 text-sm bg-[--color-bg-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-[--color-text-primary] placeholder:text-[--color-text-muted] outline-none transition-all focus:border-[--color-brand-primary] focus:shadow-[0_0_0_3px_rgba(247,81,5,0.1)]"
                                />
                            </div>
                        </div>

                        {/* Entity Type */}
                        <div className="mb-6">
                            <label className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3">
                                {t.auth.entityType}
                            </label>
                            <div className="grid grid-cols-2 gap-3">
                                <button
                                    type="button"
                                    onClick={() => setEntityType("individual")}
                                    className={cn(
                                        "py-3 text-sm font-semibold rounded-[var(--radius-md)] transition-all duration-200 cursor-pointer",
                                        entityType === "individual"
                                            ? "bg-[--color-brand-primary] text-white"
                                            : "bg-transparent text-[--color-text-primary] border border-[--color-border-default] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]"
