input.content:
"use client";

import { useState, useEffect } from "react";
import { SiteHeader } from "@/components/layout/site-header";
import { useProfile } from "@/hooks/use-profile";
import { useAuth } from "@/providers/auth-provider";
import { useLanguageStore } from "@/store/language-store";
import { useRouter } from "next/navigation";
import { Loader2, User, FlaskConical } from "lucide-react";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

export default function SettingsPage() {
    const router = useRouter();
    const { user, isLoading: authLoading } = useAuth();
    const { t } = useLanguageStore();
    const { profile, updateProfile, createProfile } = useProfile();

    const [displayName, setDisplayName] = useState("");
    const [entityType, setEntityType] = useState<"individual" | "company">("individual");
    const [labName, setLabName] = useState("");
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (!authLoading && !user) router.push("/");
    }, [user, authLoading, router]);

    useEffect(() => {
        if (profile) {
            setDisplayName(profile.display_name || "");
            setEntityType(profile.entity_type || "individual");
            setLabName(profile.lab_name || "");
        }
    }, [profile]);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        try {
            const data = { display_name: displayName, entity_type: entityType, lab_name: labName };
            if (profile) {
                await updateProfile(data);
            } else {
                await createProfile(data);
            }
            toast.success(t.settings.saved);
        } catch (error: any) {
            toast.error(t.settings.error, { description: error.message });
        } finally {
            setIsSaving(false);
        }
    };

    if (authLoading) {
        return (
            <div className="min-h-screen bg-background text-foreground font-sans">
                <SiteHeader variant="app" />
                <main className="pt-12 pb-40 px-8 w-full max-w-[800px] mx-auto flex items-center justify-center">
                    <Loader2 className="w-6 h-6 animate-spin text-[--color-text-muted]" />
                </main>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background text-foreground font-sans flex flex-col overflow-x-hidden">
            <SiteHeader variant="app" />

            <main className="relative z-[1] flex-1 pt-12 pb-40 px-8 w-full max-w-[800px] mx-auto">

                {/* .section-header — brand book: mb space-12 */}
                <div className="mb-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                    {/* .section-title — 3rem / 300 / 1.1 / mb space-4 */}
                    <h1 className="text-[3rem] font-light leading-[1.1] text-[--color-text-primary] mb-4">
                        {t.settings.title}
                    </h1>
                    {/* .section-description — 1.125rem / 300 / text-secondary / 1.6 / max-w 800 */}
                    <p className="text-[1.125rem] font-light leading-[1.6] text-[--color-text-secondary]">
                        {t.settings.subtitle}
                    </p>
                </div>

                {/* .card — bg-card / border border-default / radius-2xl / padding space-8 / transition 0.3s */}
                <div
                    className="rounded-[var(--radius-2xl)] p-8 animate-in fade-in slide-in-from-bottom-4 duration-500"
                    style={{
                        background: "var(--color-bg-card)",
                        border: "1px solid var(--color-border-default)",
                        transition: "all 0.3s ease",
                    }}
                >
                    <form onSubmit={handleSave}>

                        {/* Display Name */}
                        <div className="mb-6">
                            {/* Label — .caption register: 0.75rem / 0.02em / uppercase for form context */}
                            <label
                                htmlFor="settings-display-name"
                                className="block text-[0.75rem] font-semibold uppercase tracking-[0.1em] leading-[1.4] text-[--color-text-muted] mb-3"
                            >
                                {t.auth.displayName}
                            </label>
                            {/* .input — bg-secondary / border-default / radius-md / 0.875rem / transition 0.2s */}
                            {/* focus: border brand-primary + 3px glow */}
                            <div className="relative group">
                                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[--color-text-muted] group-focus-within:text-[--color-brand-primary] transition-colors duration-200" />
                                <input
                                    id="settings-display-name"
                                    type="text"
                                    placeholder={t.settings.displayNamePlaceholder}
                                    value={displayName}
                                    onChange={(e) => setDisplayName(e.target.value)}
                                    className="w-full pl-11 pr-4 py-3 text-[0.875rem] bg-[--color-bg-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-[--color-text-primary] placeholder:text-[--color-text-muted] outline-none transition-all duration-200 focus:border-[--color-brand-primary] focus:shadow-[0_0_0_3px_rgba(247,81,5,0.1)]"
                                />
                            </div>
                        </div>

                        {/* Entity Type */}
                        <div className="mb-6">
                            <label className="block text-[0.75rem] font-semibold uppercase tracking-[0.1em] leading-[1.4] text-[--color-text-muted] mb-3">
                                {t.auth.entityType}
                            </label>
                            {/* Toggle: .btn-primary (active) / .btn-secondary (inactive) */}
                            <div className="grid grid-cols-2 gap-3">
                                <button
                                    type="button"
                                    onClick={() => setEntityType("individual")}
                                    className={cn(
                                        "inline-flex items-center justify-center gap-2 py-3 px-6 text-[0.875rem] font-semibold rounded-[var(--radius-md)] cursor-pointer transition-all duration-200",
                                        entityType === "individual"
                                            ? "bg-[--color-brand-primary] text-white border-0"
                                            : "bg-transparent text-[--color-text-primary] border border-[--color-border-default] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]"
                                    )}
                                >
                                    {t.auth.entityIndividual}
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setEntityType("company")}
                                    className={cn(
                                        "inline-flex items-center justify-center gap-2 py-3 px-6 text-[0.875rem] font-semibold rounded-[var(--radius-md)] cursor-pointer transition-all duration-200",
                                        entityType === "company"
                                            ? "bg-[--color-brand-primary] text-white border-0"
                                            : "bg-transparent text-[--color-text-primary] border border-[--color-border-default] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]"
                                    )}
                                >
                                    {t.auth.entityCompany}
                                </button>
                            </div>
                        </div>

                        {/* Lab Name */}
