                    }}
                >
                    <h1 className="text-[2.5rem] font-light text-[--color-text-primary] tracking-[-0.02em] leading-[1.1] mb-2">
                        {t.settings.title}
                    </h1>
                    <p className="text-base text-[--color-text-muted]">
                        {t.settings.subtitle}
                    </p>
                </div>

                {/* Form card — elevated surface, brand book .card spec */}
                <div
                    className="rounded-[var(--radius-2xl)] p-8 animate-in fade-in slide-in-from-bottom-4 duration-500"
                    style={{
                        background: "var(--color-bg-card)",
                        border: "1px solid var(--color-border-default)",
                    }}
                >
                    <form onSubmit={handleSave}>

                        {/* Display Name */}
                        <div className="mb-6">
                            <label
                                htmlFor="settings-display-name"
                                className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3"
                            >
                                {t.auth.displayName}
                            </label>
                            <div className="relative group">
                                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[--color-text-muted] group-focus-within:text-[--color-brand-primary] transition-colors" />
                                <input
                                    id="settings-display-name"
                                    type="text"
                                    placeholder={t.settings.displayNamePlaceholder}
                                    value={displayName}
                                    onChange={(e) => setDisplayName(e.target.value)}
                                    className="w-full pl-11 pr-4 py-3 text-sm bg-[--color-bg-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-[--color-text-primary] placeholder:text-[--color-text-muted] outline-none transition-all focus:border-[--color-brand-primary] focus:shadow-[0_0_0_3px_rgba(247,81,5,0.1)]"
                                />
                            </div>
                        </div>

                        {/* Entity Type */}
                        <div className="mb-6">
                            <label className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3">
                                {t.auth.entityType}
                            </label>
                            <div className="grid grid-cols-2 gap-3">
                                <button
                                    type="button"
                                    onClick={() => setEntityType("individual")}
                                    className={cn(
                                        "py-3 text-sm font-semibold rounded-[var(--radius-md)] transition-all duration-200 cursor-pointer",
                                        entityType === "individual"
                                            ? "bg-[--color-brand-primary] text-white"
                                            : "bg-transparent text-[--color-text-primary] border border-[--color-border-default] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]"
                                    )}
                                >
                                    {t.auth.entityIndividual}
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setEntityType("company")}
                                    className={cn(
                                        "py-3 text-sm font-semibold rounded-[var(--radius-md)] transition-all duration-200 cursor-pointer",
                                        entityType === "company"
                                            ? "bg-[--color-brand-primary] text-white"
                                            : "bg-transparent text-[--color-text-primary] border border-[--color-border-default] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]"
                                    )}
                                >
                                    {t.auth.entityCompany}
                                </button>
                            </div>
                        </div>

                        {/* Lab Name */}
                        <div className="mb-8">
                            <label
                                htmlFor="settings-lab-name"
                                className="block text-[0.6875rem] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-3"
                            >
                                {t.auth.labName}
                            </label>
                            <div className="relative group">
                                <FlaskConical className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[--color-text-muted] group-focus-within:text-[--color-brand-primary] transition-colors" />
                                <input
                                    id="settings-lab-name"
                                    type="text"
                                    placeholder={t.settings.labNamePlaceholder}
                                    value={labName}
                                    onChange={(e) => setLabName(e.target.value)}
                                    className="w-full pl-11 pr-4 py-3 text-sm bg-[--color-bg-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-[--color-text-primary] placeholder:text-[--color-text-muted] outline-none transition-all focus:border-[--color-brand-primary] focus:shadow-[0_0_0_3px_rgba(247,81,5,0.1)]"
                                />
                            </div>
                        </div>

                        {/* Save */}
                        <button
                            type="submit"
                            disabled={isSaving}
                            className={cn(
                                "inline-flex items-center gap-2 py-3 px-6 text-sm font-semibold rounded-[var(--radius-md)] transition-all duration-200 cursor-pointer",
                                isSaving
                                    ? "bg-[--color-brand-primary]/50 text-white/50 cursor-not-allowed"
                                    : "bg-[--color-brand-primary] text-white hover:bg-[--color-brand-secondary] hover:shadow-[0_0_30px_rgba(247,81,5,0.3)] hover:-translate-y-[1px]"
                            )}
                        >
                            {isSaving && <Loader2 className="w-4 h-4 animate-spin" />}
                            {isSaving ? t.settings.saving : t.settings.save}
                        </button>
                    </form>
                </div>

            </main>
        </div>
    );
}
